        public String build() {
            NUIForm form = AppManager.getFormPage(this.apname, this.path, this.sheetIndex,true);
            StringBuffer sb = new StringBuffer();
            try {
                sb.append("BEGIN:VCALENDAR\n");
                sb.append("PRODID:-//Ragic Inc//Ragic v6//EN\n");
                sb.append("VERSION:2.0\n");
                sb.append("CALSCALE:GREGORIAN\n");
                sb.append("METHOD:PUBLISH\n");
                sb.append("X-WR-CALNAME:").append(form.getRealname()).append("\n");
                sb.append("X-WR-TIMEZONE:\n");
                sb.append("X-WR-CALDESC:\n");

                if(this.applyDST) {
                    StringBuilder vtimezone = downloadVTimezone(false);
                    if(vtimezone.length() == 0) vtimezone = downloadVTimezone(true);
                    if(vtimezone.length() > 0) {
                        sb.append(vtimezone);
                    } else {
                        logger.error("iCal_v2 download VTIMEZONE failed");
                        return "";
                    }
                }

                StringBuilder vevents = getVEvents(form);
                sb.append(vevents);
                sb.append("END:VCALENDAR");
            } catch(Exception e) {
                logger.error("Building ical failed");
                logger.error(e);
                ExceptionManager.getInstance().processException(e);
            }
            return sb.toString();
        }

        private StringBuilder downloadVTimezone(boolean convertToEtcGMT) {
            StringBuilder vtimezone = new StringBuilder();
            try {
                // Download vtimezone from tzurl.org
                URL tzurl;
                if(!convertToEtcGMT) {
                    tzurl = new URL("http://static.tzurl.org/zoneinfo/" + this.timezoneId + ".ics");
                } else {
                    int tzOffsetInHour = (int)com.ragic.s3.util.Util.getTimeZoneOffset(this.timezoneId)/1000/60/60;
                    tzurl = new URL("http://static.tzurl.org/zoneinfo/Etc/GMT" + (tzOffsetInHour >= 0? "+" :"") + tzOffsetInHour + ".ics");
                }

                try(BufferedReader reader = new BufferedReader(new InputStreamReader(tzurl.openStream()))) {
                    String nextLine = null;
                    boolean append = false;
                    while(true) {
                        nextLine = reader.readLine();
                        if(nextLine == null) break;
                        if(nextLine.startsWith("BEGIN:VTIMEZONE")) {
                            append = true;
                        } else if(nextLine.startsWith("END:VTIMEZONE")) {
                            vtimezone.append(nextLine);
                            vtimezone.append("\n");
                            append = false;
                        }
                        if(append) {
                            vtimezone.append(nextLine);
                            vtimezone.append("\n");
                        }
                    }
                }

            } catch(Exception e) {
                vtimezone = new StringBuilder(); // clear vtimezone
            }
            return vtimezone;
        }

