  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html; charset=UTF-8");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    RequestParam rp = (RequestParam) request.getAttribute("REQ");

    Log icalV2Log = Log.createStandardLog().setLevel(Log.WARN)
            .setFilePath(Log.MaintenanceLog.RAGIC_ICALV2_LOG.getFilePath(rp.getApname()));
    icalV2Log.debug("Generating ical...");

    String userString = request.getParameter("u");
    if (userString == null) {
        icalV2Log.warn("iCal_v2 user string not found.");
        return;
    }
//userString = userString.replaceAll(" ", "\\+");
    userString = new DES().decrypt(userString);
    icalV2Log.debug("userString=" + userString);

    userString = userString.substring(8);
    User user = RemoteAccountManager.main_userInfo(userString);
    if (user == null) {
        icalV2Log.warn("iCal_v2 user " + userString + " remote login failed.");
        return;
    }

    APIQuery aq = new APIQuery(rp.getApname(), rp.getPath(), rp.getSheetIndex());
    if(aq.getForm()==null) {
        icalV2Log.warn("iCal_v2 form not found: " + rp.getApname() + rp.getPath() + "/" + rp.getSheetIndex());
        return;
    }

    JSONArray selectedEvents = null;
    try {
        selectedEvents = new JSONArray(request.getParameter("y"));
    } catch(Exception e) {
        icalV2Log.error("iCal_v2 get selected domains failed: " + e.getMessage());
        icalV2Log.error(e);
        ExceptionManager.getInstance().processException(e);
        return;
    }
    icalV2Log.debug("Selected events=\n" + selectedEvents.toString(4));

    String timezoneId = request.getParameter("tz");
    if(timezoneId == null) {
        icalV2Log.warn("iCal_v2 get timezond id failed");
        timezoneId= Account.getInstance(aq.getApname()).getAppSetting().getTimeZone();
    }
    icalV2Log.debug("timezone id=" + timezoneId);

    boolean applyDST = Encoder.parseBoolean(request.getParameter("applyDST"), true);
    icalV2Log.debug("applyDST=" + applyDST);

    boolean displayRecordUrlInDescription = Encoder.parseBoolean(request.getParameter("displayRecordUrlInDescription"), true);

    RagicICalendarBuilder builder = new RagicICalendarBuilder(
            rp.getApname(),
            rp.getPath(),
            rp.getSheetIndex(),
            user,
            timezoneId,
            applyDST,
            displayRecordUrlInDescription,
            selectedEvents);
    out.print(builder.build());

    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
